INSERT INTO gallery (id, title, description, url) VALUES
('gal-1', 'Model Live2D Key Visual Reveal (Casual Style)', 'Pose render orisinal model Live2D Intan gaya casual sci-fi yang pertama kali diperkenalkan saat debut stream.', 'https://images.unsplash.com/photo-1618005182384-a83a8bd57fbe?w=600&auto=format&fit=crop&q=80'),
('gal-2', 'Minecraft Multiplayer Castle Stage View', 'Screenshot kastil megah berbahan ungu yang dibangun bersama para member komunitas IRIS di server Survival.', 'https://images.unsplash.com/photo-1544947950-fa07a98d237f?w=600&auto=format&fit=crop&q=80'),
('gal-3', 'Matcha Vibes Chill Cover Artwork Canvas', 'Kanvas artwork ilustrasi digital promo rilisan EP Album Matcha Vibes Lofi Chill.', 'https://images.unsplash.com/photo-1518609878373-06d740f60d8b?w=600&auto=format&fit=crop&q=80'),
('gal-4', 'Special Concert Fan Meeting Virtual Room', 'Screenshot keramaian member dalam room virtual meet and greet konser ulang tahun debut Intan.', 'https://images.unsplash.com/photo-1511671782779-c97d3d27a1d4?w=600&auto=format&fit=crop&q=80');
INSERT INTO playlists (id, title, description, image_url, category, badge_text, duration, tracks_count, embed_url, spotify_url, spotify_embed_url, curator_note, created_at) VALUES
('2aMGqrDZrqERqgMPIQe0ui', 'Ongoing New Playlist', 'Kumpulan lagu pilihan terbaru untuk menemani hari-harimu di #DengerINTAN.', 'https://images.unsplash.com/photo-1614613535308-eb5fbd3d2c17?q=80&w=600&auto=format&fit=crop', 'Juni 2026', 'Ongoing Playlist', '2h 00m', '30 Tracks', 'https://www.youtube.com/embed/videoseries?list=PL3-sRM8xAzY-oQj01w4_mY6-x6H2bE3X1', 'https://open.spotify.com/playlist/2aMGqrDZrqERqgMPIQe0ui', 'https://open.spotify.com/embed/playlist/2aMGqrDZrqERqgMPIQe0ui?utm_source=generator', 'Hai IRIS! Ini playlist Ongoing terbaru khusus buat nemenin aktivitas kalian bulan ini. Selamat mendengarkan! ✨', NOW()),
('4jLqcyPlFe7hdFFOr1r0ML', 'Archive Playlist Vol. 3', 'Arsip keseruan dan memori lagu-lagu pilihan dari edisi #DengerINTAN sebelumnya.', 'https://images.unsplash.com/photo-1511671782779-c97d3d27a1d4?q=80&w=600&auto=format&fit=crop', 'Mei 2026', 'Archive Playlist', '1h 45m', '25 Tracks', 'https://www.youtube.com/embed/videoseries?list=PL3-sRM8xAzY-oQj01w4_mY6-x6H2bE3X1', 'https://open.spotify.com/playlist/4jLqcyPlFe7hdFFOr1r0ML', 'https://open.spotify.com/embed/playlist/4jLqcyPlFe7hdFFOr1r0ML?utm_source=generator', 'Halo semuanya! Ini adalah arsip playlist bulan lalu. Tetap asyik buat didengerin ulang sambil santai atau nugas kok! 🎧', NOW() - INTERVAL '1 month'),
('6azVHz2MOw9d0oJrZxmpul', 'Archive Playlist Vol. 2', 'Arsip keseruan dan memori lagu-lagu pilihan dari edisi #DengerINTAN sebelumnya.', 'https://images.unsplash.com/photo-1487180142328-054b783fc471?q=80&w=600&auto=format&fit=crop', 'April 2026', 'Archive Playlist', '2h 15m', '35 Tracks', 'https://www.youtube.com/embed/videoseries?list=PL3-sRM8xAzY-oQj01w4_mY6-x6H2bE3X1', 'https://open.spotify.com/playlist/6azVHz2MOw9d0oJrZxmpul', 'https://open.spotify.com/embed/playlist/6azVHz2MOw9d0oJrZxmpul?utm_source=generator', 'Kumpulan lagu penuh memori dari kurasi edisi lalu. Jangan lupa cek track favorit kalian di sini ya! 🎸', NOW() - INTERVAL '2 months'),
('1zpGEcM4GlAyz4kpvjJUK9', 'Archive Playlist Vol. 1', 'Arsip keseruan dan memori lagu-lagu pilihan dari edisi #DengerINTAN sebelumnya.', 'https://images.unsplash.com/photo-1514525253161-7a46d19cd819?q=80&w=600&auto=format&fit=crop', 'Maret 2026', 'Archive Playlist', '1h 30m', '20 Tracks', 'https://www.youtube.com/embed/videoseries?list=PL3-sRM8xAzY-oQj01w4_mY6-x6H2bE3X1', 'https://open.spotify.com/playlist/1zpGEcM4GlAyz4kpvjJUK9', 'https://open.spotify.com/embed/playlist/1zpGEcM4GlAyz4kpvjJUK9?utm_source=generator', 'Kilas balik ke playlist awal #DengerINTAN. Isinya lagu-lagu nostalgic yang bakal bikin kamu ikutan sing-along! 🎤☀️', NOW() - INTERVAL '3 months'),
('7ts54pSqOxEqK7Mcr7wsPf', 'Archive Playlist Vol. 5', 'Arsip keseruan dan memori lagu-lagu pilihan dari edisi #DengerINTAN sebelumnya.', 'https://images.unsplash.com/photo-1511671782779-c97d3d27a1d4?q=80&w=600&auto=format&fit=crop', 'Februari 2026', 'Archive Playlist', '2h 05m', '28 Tracks', 'https://www.youtube.com/embed/videoseries?list=PL3-sRM8xAzY-oQj01w4_mY6-x6H2bE3X1', 'https://open.spotify.com/playlist/7ts54pSqOxEqK7Mcr7wsPf', 'https://open.spotify.com/embed/playlist/7ts54pSqOxEqK7Mcr7wsPf?utm_source=generator', 'Koleksi tambahan arsip lagu kurasi pilihan untuk menemani waktu santaimu bersama #DengerINTAN. 🎶', NOW() - INTERVAL '4 months'),
('3ylSh5l2hqkakZqX09FAFL', 'Archive Playlist Vol. 6', 'Arsip keseruan dan memori lagu-lagu pilihan dari edisi #DengerINTAN sebelumnya.', 'https://images.unsplash.com/photo-1487180142328-054b783fc471?q=80&w=600&auto=format&fit=crop', 'Januari 2026', 'Archive Playlist', '1h 50m', '24 Tracks', 'https://www.youtube.com/embed/videoseries?list=PL3-sRM8xAzY-oQj01w4_mY6-x6H2bE3X1', 'https://open.spotify.com/playlist/3ylSh5l2hqkakZqX09FAFL', 'https://open.spotify.com/embed/playlist/3ylSh5l2hqkakZqX09FAFL?utm_source=generator', 'Koleksi tambahan arsip lagu kurasi pilihan untuk menemani waktu santaimu bersama #DengerINTAN. 🎶', NOW() - INTERVAL '5 months');
